class Session(dict[str, typing.Any]):
    accessed: bool = False
    modified: bool = False

    def mark_accessed(self) -> None:
        self.accessed = True

    def mark_modified(self) -> None:
        self.accessed = True
        self.modified = True

    def __setitem__(self, key: str, value: typing.Any) -> None:
        self.mark_modified()
        super().__setitem__(key, value)

    def __delitem__(self, key: str) -> None:
        self.mark_modified()
        super().__delitem__(key)

    def clear(self) -> None:
        self.mark_modified()
        super().clear()

    def pop(self, key: str, *args: typing.Any) -> typing.Any:
        self.modified = self.modified or key in self
        return super().pop(key, *args)

    def setdefault(self, key: str, default: typing.Any = None) -> typing.Any:
        if key not in self:
            self.mark_modified()
        return super().setdefault(key, default)

    def update(self, *args: typing.Any, **kwargs: typing.Any) -> None:
        self.mark_modified()
        super().update(*args, **kwargs)

async def __aexit__(
        self,
        exc_type: type[BaseException] | None = None,
        exc_val: BaseException | None = None,
        exc_tb: Optional["TracebackType"] = None,
    ) -> bool | None:
        if self.ack_policy is AckPolicy.ACK_FIRST:
            return False

        if not exc_type:
            await self.__ack()

        elif isinstance(exc_val, HandlerException):
            if isinstance(exc_val, AckMessage):
                await self.__ack(**exc_val.extra_options)

            elif isinstance(exc_val, NackMessage):
                await self.__nack(**exc_val.extra_options)

            elif isinstance(exc_val, RejectMessage):  # pragma: no branch
                await self.__reject(**exc_val.extra_options)

            # Exception was processed and suppressed
            return True

        elif self.ack_policy is AckPolicy.REJECT_ON_ERROR:
            await self.__reject()

        elif self.ack_policy is AckPolicy.NACK_ON_ERROR:
            await self.__nack()

        elif self.ack_policy is AckPolicy.ACK:
            await self.__ack()

        # Exception was not processed
        return False

class BaseRawParams:
    type: ClassVar[ParamsType]
    include_total: bool

    def as_limit_offset(self) -> RawParams:
        if is_limit_offset(self):
            return self

        raise ValueError("Not a 'limit-offset' params")

    def as_cursor(self) -> CursorRawParams:
        if is_cursor(self):
            return self

        raise ValueError("Not a 'cursor' params")


def is_limit_offset(params: BaseRawParams) -> TypeIs[RawParams]:
    return params.type == "limit-offset"


def is_cursor(params: BaseRawParams) -> TypeIs[CursorRawParams]:
    return params.type == "cursor"


@dataclass
class RawParams(BaseRawParams):
    limit: int | None = None
    offset: int | None = None
    include_total: bool = True

    type: ClassVar[ParamsType] = "limit-offset"

    def as_slice(self) -> slice:
        return slice(
            self.offset,
            (self.offset or 0) + self.limit if self.limit is not None else None,
        )

@dataclass
class UseIncludeTotal(PageCustomizer):
    include_total: bool

    update_annotations: bool = True
    affected_fields: Sequence[str] = (
        "total",
        "page",
        "size",
        "pages",
        "limit",
        "offset",
    )

    def customize_page_ns(self, page_cls: PageCls, ns: ClsNamespace) -> None:
        include_total = self.include_total

        if TYPE_CHECKING:
            from .bases import AbstractParams as ParamsCls
        else:
            ParamsCls = ns["__params_type__"]

        class CustomizedParams(ParamsCls):
            def to_raw_params(self) -> BaseRawParams:
                raw_params = super().to_raw_params()
                raw_params.include_total = include_total

                return raw_params

        ns["__params_type__"] = CustomizedParams

        if self.update_annotations:
            customizer = _UseOptionalRequiredFields(
                required=self.include_total,
                fields=self.affected_fields,
            )
            customizer.customize_page_ns(page_cls, ns)

@dataclass
class UseFlattenPage(PostPageTransformer):
    field: str = "items"

    def post_transform_page_cls(self, page_cls: PageCls) -> PageCls:
        _is_pydantic_v2 = is_pydantic_v2_model(page_cls)

        if _is_pydantic_v2:  # noqa: SIM108
            base_cls = RootModel[list[_T]]
        else:  # pragma: no cover
            base_cls = RootModel

        class _FlattenPage(AbstractPage[_T], base_cls):  # type: ignore[ty:invalid-base]
            if not _is_pydantic_v2:  # pragma: no cover
                __root__: list[_T]

            __params_type__ = page_cls.__params_type__

            @classmethod
            def create(
                cls,
                items: Sequence[_T],
                params: AbstractParams,
                **kwargs: Any,
            ) -> Self:
                page = page_cls.create(items, params, **kwargs)
                items = getattr(page, self.field)

                if _is_pydantic_v2:
                    return cls(items)  # type: ignore[ty:missing-argument]  # type: ignore[ty:too-many-positional-arguments]

                return cls.parse_obj(items)  # pragma: no cover

        return cast(PageCls, _FlattenPage)

def _unwrap_message_to_fast_depends_decorator(
    func: Callable[..., Any],
    dependent: "CallModel",
) -> Callable[["StreamMessage[Any]"], Awaitable[Any]]:
    dependant_params = dependent.flat_params
    if len(dependant_params) <= 1:
        if option := next(iter(dependant_params), None):
            is_multi_params = option.kind is inspect.Parameter.VAR_POSITIONAL
        else:
            is_multi_params = False
    else:
        is_multi_params = True

    if is_multi_params:

        async def decode_wrapper(message: "StreamMessage[Any]") -> Any:
            msg = await message.decode()

            if isinstance(msg, Mapping):
                return await func(**msg)

            if isinstance(msg, Sequence):
                return await func(*msg)

            msg = f"Couldn't unpack `{msg}` to multiple values."
            raise ValueError(msg)

    else:

        async def decode_wrapper(message: "StreamMessage[Any]") -> Any:
            msg = await message.decode()
            return await func(msg)

    return decode_wrapper

def load_application(path: str, wsgi_max_body_size: int) -> AppWrapper:
    mode: Literal["asgi", "wsgi"] | None = None
    if ":" not in path:
        module_name, app_name = path, "app"
    elif path.count(":") == 2:
        mode, module_name, app_name = path.split(":", 2)  # type: ignore
        if mode not in {"asgi", "wsgi"}:
            raise ValueError("Invalid mode, must be 'asgi', or 'wsgi'")
    else:
        module_name, app_name = path.split(":", 1)

    module_path = Path(module_name).resolve()
    sys.path.insert(0, str(module_path.parent))
    if module_path.is_file():
        import_name = module_path.with_suffix("").name
    else:
        import_name = module_path.name
    try:
        module = import_module(import_name)
    except ModuleNotFoundError as error:
        if error.name == import_name:
            raise NoAppError(f"Cannot load application from '{path}', module not found.")
        else:
            raise
    try:
        app = eval(app_name, vars(module))
    except NameError:
        raise NoAppError(f"Cannot load application from '{path}', application not found.")
    else:
        return wrap_app(app, wsgi_max_body_size, mode)

Flow: TypeAlias = Generator[
    Awaitable[TArg] | TArg,
    TArg,
    R,
]
AnyFlow: TypeAlias = Flow[Any, R]

TFlow = TypeVar("TFlow", bound=Flow[Any, Any])


def flow(func: Callable[P, TFlow]) -> Callable[P, TFlow]:
    return func


def _check_not_coro(obj: Any) -> None:
    if is_coro(obj):
        raise TypeError(f"Coroutine {obj} is not allowed in sync flow")


def run_sync_flow(gen: Flow[Any, R], /) -> R:
    try:
        res = gen.send(None)
        _check_not_coro(res)

        while True:
            try:
                res = gen.send(res)
                _check_not_coro(res)
            except StopIteration:  # noqa: PERF203
                raise
            except BaseException as exc:  # noqa: BLE001
                res = gen.throw(exc)
    except StopIteration as exc:
        return cast(R, exc.value)


async def run_async_flow(gen: Flow[Any, R], /) -> R:
    try:
        res = gen.send(None)

        while True:
            try:
                res = await await_if_coro(res)
                res = gen.send(res)
            except StopIteration:  # noqa: PERF203
                raise
            except BaseException as exc:  # noqa: BLE001
                res = gen.throw(exc)
    except StopIteration as exc:
        return cast(R, exc.value)

def __enter__(self: _SupportsCtxMgr[_T_co, bool | None]) -> _T_co:
        # Needed for mypy to assume self still has the __cm member
        assert isinstance(self, ContextManagerMixin)
        if self.__cm is not None:
            raise RuntimeError(
                f"this {self.__class__.__qualname__} has already been entered"
            )

        cm = self.__contextmanager__()
        if not isinstance(cm, AbstractContextManager):
            if isgenerator(cm):
                raise TypeError(
                    "__contextmanager__() returned a generator object instead of "
                    "a context manager. Did you forget to add the @contextmanager "
                    "decorator?"
                )

            raise TypeError(
                f"__contextmanager__() did not return a context manager object, "
                f"but {cm.__class__!r}"
            )

        if cm is self:
            raise TypeError(
                f"{self.__class__.__qualname__}.__contextmanager__() returned "
                f"self. Did you forget to add the @contextmanager decorator and a "
                f"'yield' statement?"
            )

        value = cm.__enter__()
        self.__cm = cm
        return value

def __init__(
        self,
        *,
        settings_provider_factory: Callable[
            [AnyMsg | None],
            MetricsSettingsProvider[AnyMsg, PublishCommandType] | None,
        ],
        registry: "CollectorRegistry",
        app_name: str = EMPTY,
        metrics_prefix: str = "faststream",
        received_messages_size_buckets: Sequence[float] | None = None,
        custom_labels: dict[str, str | Callable[[Any], str]] | None = None,
    ) -> None:
        if app_name is EMPTY:
            app_name = metrics_prefix

        self._settings_provider_factory = settings_provider_factory
        self._metrics_container = MetricsContainer(
            registry,
            metrics_prefix=metrics_prefix,
            received_messages_size_buckets=received_messages_size_buckets,
            custom_label_names=tuple((custom_labels or {}).keys()),
        )
        self._metrics_manager = MetricsManager(
            self._metrics_container,
            app_name=app_name,
        )
        self._static_labels = {}
        self._dynamic_labels = {}

        for k, v in (custom_labels or {}).items():
            if callable(v):
                self._dynamic_labels[k] = v
            else:
                self._static_labels[k] = v

